            try {
                byte[] fileContent = Files.readAllBytes(file.toPath());
                System.out.println("File content: " + new String(fileContent));
            } catch (IOException e) {
                System.err.println("Error reading file.");
            }
        } else {
            System.err.println("File not found.");
        }

