import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.util.Scanner;

public class PathTraversalSecure {

    private static final String BASE_DIRECTORY = "/path/to/secure/directory";

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter file name:");
        String fileName = scanner.nextLine();

        File requestedFile = new File(BASE_DIRECTORY + File.separator + fileName).getCanonicalFile();

        if (requestedFile.getPath().startsWith(BASE_DIRECTORY) && requestedFile.exists()) {
            try {
                byte[] fileContent = Files.readAllBytes(requestedFile.toPath());
                System.out.println("File content: " + new String(fileContent));
            } catch (IOException e) {
                System.err.println("Error reading file.");
            }
        } else {
            System.err.println("File not found or access denied.");
        }

        scanner.close();
    }
}

